import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {

  const LOG_COUNT = 50;
  const HOSTNAME  = 'ASA-EDGE-01';
  const DEVICE_IP = '10.0.0.1';

  const INTERNAL_SUBNETS = [
    { net: '10.0.1',   intf: 'inside',   label: 'LAN' },
    { net: '10.0.2',   intf: 'dmz',      label: 'DMZ' },
    { net: '172.16.5', intf: 'vpn-pool', label: 'VPN' },
  ];

  const EXTERNAL_SUBNETS = [
    { net: '203.0.113', intf: 'outside' },
    { net: '198.51.100', intf: 'outside' },
    { net: '192.0.2',   intf: 'outside' },
  ];

  const SERVICES = [
    { port: 443, proto: 'TCP',  name: 'HTTPS' },
    { port: 80,  proto: 'TCP',  name: 'HTTP'  },
    { port: 22,  proto: 'TCP',  name: 'SSH'   },
    { port: 53,  proto: 'UDP',  name: 'DNS'   },
    { port: 3389, proto: 'TCP', name: 'RDP'   },
    { port: 445, proto: 'TCP',  name: 'SMB'   },
    { port: 1433, proto: 'TCP', name: 'MSSQL' },
    { port: 25,  proto: 'TCP',  name: 'SMTP'  },
    { port: 21,  proto: 'TCP',  name: 'FTP'   },
    { port: 23,  proto: 'TCP',  name: 'Telnet'},
    { port: 8080, proto: 'TCP', name: 'HTTP-Alt' },
  ];

  const TEARDOWN_REASONS = [
    'TCP FINs', 'TCP Reset - I', 'TCP Reset - O', 'Conn-timeout',
    'Idle Timeout', 'FIN Timeout', 'SYN Timeout', 'User Requested',
  ];

  const VPN_GROUPS = ['RemoteAccess-Users', 'Site2Site-Partners', 'Contractors'];
  const VPN_USERS  = [
    'alice.smith', 'bob.johnson', 'carol.white', 'dave.brown',
    'eve.jones', 'frank.davis', 'grace.miller', 'henry.wilson',
  ];

  const ACL_NAMES = [
    'OUTSIDE-IN', 'INSIDE-OUT', 'DMZ-POLICY', 'VPN-FILTER',
  ];

  // IPS/Snort signatures (Cisco Firepower / FTD style)
  const IPS_SIGNATURES = [
    { sid: '1-30001', msg: 'ET EXPLOIT MS17-010 EternalBlue SMB RCE Attempt',       sev: 2, priority: 'high',     cve: 'CVE-2017-0144' },
    { sid: '1-30002', msg: 'ET MALWARE Cobalt Strike Beacon Activity',               sev: 2, priority: 'high',     cve: '' },
    { sid: '1-30003', msg: 'ET EXPLOIT Log4Shell JNDI LDAP Outbound Attempt',        sev: 1, priority: 'critical', cve: 'CVE-2021-44228' },
    { sid: '1-30004', msg: 'ET SCAN SSH Brute Force Login Attempt',                  sev: 3, priority: 'medium',   cve: '' },
    { sid: '1-30005', msg: 'ET EXPLOIT BlueKeep RDP Remote Code Execution',          sev: 1, priority: 'critical', cve: 'CVE-2019-0708' },
    { sid: '1-30006', msg: 'ET WEB_SERVER SQL Injection Attempt UNION SELECT',       sev: 3, priority: 'medium',   cve: '' },
    { sid: '1-30007', msg: 'ET MALWARE Suspicious PE File Transfer',                 sev: 2, priority: 'high',     cve: '' },
    { sid: '1-30008', msg: 'ET DNS Possible DNS Tunneling C2 Beacon',                sev: 3, priority: 'medium',   cve: '' },
    { sid: '1-30009', msg: 'ET EXPLOIT Apache Struts OGNL Injection Attack',         sev: 2, priority: 'high',     cve: 'CVE-2017-5638' },
    { sid: '1-30010', msg: 'ET POLICY FTP Bounce Attack Detected',                   sev: 3, priority: 'low',      cve: '' },
  ];

  // Platform/System event messages
  const SYSTEM_EVENTS = [
    { msgid: '104001', sev: 3, msg: 'Switching to active - primary unit is down' },
    { msgid: '104002', sev: 4, msg: 'Switching to standby - peer unit recovered' },
    { msgid: '105001', sev: 5, msg: 'Heartbeat status recovered from peer unit' },
    { msgid: '105003', sev: 3, msg: 'Heartbeat still missing after 30 seconds from peer unit' },
    { msgid: '111008', sev: 5, msg: `User 'admin' executed the 'show version' command.` },
    { msgid: '111010', sev: 5, msg: `User 'admin' executed the 'write memory' command.` },
    { msgid: '111009', sev: 4, msg: `User 'admin' executed the 'reload' command.` },
    { msgid: '199002', sev: 4, msg: 'Startup completed. Beginning normal operations.' },
    { msgid: '321001', sev: 2, msg: 'Process SSH is failing, 3 consecutive failed attempts. Incrementing failure count to 3' },
    { msgid: '414001', sev: 3, msg: `Dropped UDP DNS reply from outside:203.0.113.5/53 to inside:10.0.1.100/53 ; dns-guard` },
    { msgid: '501102', sev: 5, msg: `User 'admin' executed the following command: interface GigabitEthernet0/0, no shutdown` },
    { msgid: '713172', sev: 6, msg: 'Group = RemoteAccess-Users, IP = 203.0.113.50, Automatic NAT Detection Status: No, Detection NAT inside' },
  ];

  const ADMIN_IPS = ['10.0.1.50', '10.0.2.20', '172.16.5.100'];

  function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }
  function pick(arr) { return arr[randomInt(0, arr.length - 1)]; }
  function randomIp(subnet) { return `${subnet.net}.${randomInt(1, 254)}`; }
  function pad(n) { return n < 10 ? '0' + n : '' + n; }

  function fmtTimestamp(ts) {
    const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    return `${months[ts.getMonth()]} ${pad(ts.getDate())} ${pad(ts.getHours())}:${pad(ts.getMinutes())}:${pad(ts.getSeconds())}`;
  }

  function makeSyslogLine(severity, msgid, hostname, message, ts) {
    const pri = 16 * 8 + severity; // facility=16 (local0)
    return `<${pri}>${fmtTimestamp(ts)} ${hostname} : %ASA-${severity}-${msgid}: ${message}`;
  }

  // 302013 — Built TCP connection
  function build302013(ts) {
    const connId = randomInt(100000, 9999999);
    const svc  = pick(SERVICES.filter(s => s.proto === 'TCP'));
    const inbound = Math.random() < 0.5;
    const inside = pick(INTERNAL_SUBNETS);
    const outside = pick(EXTERNAL_SUBNETS);
    const srcIp   = inbound ? randomIp(outside) : randomIp(inside);
    const srcPort = randomInt(1024, 65535);
    const dstIp   = inbound ? randomIp(inside) : randomIp(outside);
    const dstPort = svc.port;
    const srcIntf = inbound ? outside.intf : inside.intf;
    const dstIntf = inbound ? inside.intf  : outside.intf;
    const dir = inbound ? 'inbound' : 'outbound';
    const msg = `Built ${dir} TCP connection ${connId} for ${srcIntf}:${srcIp}/${srcPort} (${srcIp}/${srcPort}) to ${dstIntf}:${dstIp}/${dstPort} (${dstIp}/${dstPort})`;
    return { line: makeSyslogLine(6, '302013', HOSTNAME, msg, ts), msgid: '302013', action: 'built', protocol: 'TCP', src_ip: srcIp, src_port: srcPort, dst_ip: dstIp, dst_port: dstPort, conn_id: connId };
  }

  // 302014 — Teardown TCP connection
  function build302014(ts) {
    const connId = randomInt(100000, 9999999);
    const svc  = pick(SERVICES.filter(s => s.proto === 'TCP'));
    const inside = pick(INTERNAL_SUBNETS);
    const outside = pick(EXTERNAL_SUBNETS);
    const srcIp   = randomIp(inside);
    const srcPort = randomInt(1024, 65535);
    const dstIp   = randomIp(outside);
    const dstPort = svc.port;
    const duration = `0:${pad(randomInt(0,59))}:${pad(randomInt(0,59))}`;
    const bytes    = randomInt(500, 500000);
    const reason   = pick(TEARDOWN_REASONS);
    const msg = `Teardown TCP connection ${connId} for ${inside.intf}:${srcIp}/${srcPort} to ${outside.intf}:${dstIp}/${dstPort} duration ${duration} bytes ${bytes} ${reason}`;
    return { line: makeSyslogLine(6, '302014', HOSTNAME, msg, ts), msgid: '302014', action: 'teardown', protocol: 'TCP', src_ip: srcIp, src_port: srcPort, dst_ip: dstIp, dst_port: dstPort, conn_id: connId, bytes, reason };
  }

  // 302015 — Built UDP connection
  function build302015(ts) {
    const connId = randomInt(100000, 9999999);
    const svc    = pick(SERVICES.filter(s => s.proto === 'UDP'));
    const inside = pick(INTERNAL_SUBNETS);
    const outside = pick(EXTERNAL_SUBNETS);
    const srcIp   = randomIp(inside);
    const srcPort = randomInt(1024, 65535);
    const dstIp   = randomIp(outside);
    const dstPort = svc.port;
    const msg = `Built outbound UDP connection ${connId} for ${inside.intf}:${srcIp}/${srcPort} (${srcIp}/${srcPort}) to ${outside.intf}:${dstIp}/${dstPort} (${dstIp}/${dstPort})`;
    return { line: makeSyslogLine(6, '302015', HOSTNAME, msg, ts), msgid: '302015', action: 'built', protocol: 'UDP', src_ip: srcIp, src_port: srcPort, dst_ip: dstIp, dst_port: dstPort, conn_id: connId };
  }

  // 302016 — Teardown UDP connection
  function build302016(ts) {
    const connId = randomInt(100000, 9999999);
    const svc    = pick(SERVICES.filter(s => s.proto === 'UDP'));
    const inside = pick(INTERNAL_SUBNETS);
    const outside = pick(EXTERNAL_SUBNETS);
    const srcIp   = randomIp(inside);
    const srcPort = randomInt(1024, 65535);
    const dstIp   = randomIp(outside);
    const dstPort = svc.port;
    const duration = `0:${pad(randomInt(0,59))}:${pad(randomInt(0,59))}`;
    const bytes    = randomInt(100, 50000);
    const msg = `Teardown UDP connection ${connId} for ${inside.intf}:${srcIp}/${srcPort} to ${outside.intf}:${dstIp}/${dstPort} duration ${duration} bytes ${bytes}`;
    return { line: makeSyslogLine(6, '302016', HOSTNAME, msg, ts), msgid: '302016', action: 'teardown', protocol: 'UDP', src_ip: srcIp, src_port: srcPort, dst_ip: dstIp, dst_port: dstPort, conn_id: connId, bytes };
  }

  // 106023 — ACL deny
  function build106023(ts) {
    const svc    = pick(SERVICES);
    const outside = pick(EXTERNAL_SUBNETS);
    const inside  = pick(INTERNAL_SUBNETS);
    const srcIp   = randomIp(outside);
    const srcPort = randomInt(1024, 65535);
    const dstIp   = randomIp(inside);
    const dstPort = svc.port;
    const acl     = pick(ACL_NAMES);
    const msg = `Deny ${svc.proto} src ${outside.intf}:${srcIp}/${srcPort} dst ${inside.intf}:${dstIp}/${dstPort} by access-group "${acl}" [0x0, 0x0]`;
    return { line: makeSyslogLine(4, '106023', HOSTNAME, msg, ts), msgid: '106023', action: 'deny', protocol: svc.proto, src_ip: srcIp, src_port: srcPort, dst_ip: dstIp, dst_port: dstPort, acl };
  }

  // 106100 — ACL permit
  function build106100(ts) {
    const svc    = pick(SERVICES);
    const inside  = pick(INTERNAL_SUBNETS);
    const outside = pick(EXTERNAL_SUBNETS);
    const srcIp   = randomIp(inside);
    const srcPort = randomInt(1024, 65535);
    const dstIp   = randomIp(outside);
    const dstPort = svc.port;
    const acl     = pick(ACL_NAMES);
    const hitCnt  = randomInt(1, 500);
    const msg = `access-list ${acl} permitted ${svc.proto} ${inside.intf}/${srcIp}/${srcPort} -> ${outside.intf}/${dstIp}(${dstPort}) hit-cnt ${hitCnt} first hit [0x0, 0x0]`;
    return { line: makeSyslogLine(6, '106100', HOSTNAME, msg, ts), msgid: '106100', action: 'permit', protocol: svc.proto, src_ip: srcIp, src_port: srcPort, dst_ip: dstIp, dst_port: dstPort, acl, hit_cnt: hitCnt };
  }

  // 710003 — TCP access denied by ACL (port-based block)
  function build710003(ts) {
    const svc    = pick(SERVICES.filter(s => s.proto === 'TCP'));
    const outside = pick(EXTERNAL_SUBNETS);
    const inside  = pick(INTERNAL_SUBNETS);
    const srcIp   = randomIp(outside);
    const dstIp   = DEVICE_IP;
    const dstPort = svc.port;
    const msg = `${svc.proto} access denied by ACL from ${srcIp}/${randomInt(1024,65535)} to ${inside.intf}:${dstIp}/${dstPort}`;
    return { line: makeSyslogLine(6, '710003', HOSTNAME, msg, ts), msgid: '710003', action: 'deny', protocol: svc.proto, src_ip: srcIp, dst_ip: dstIp, dst_port: dstPort };
  }

  // 113039 — AnyConnect/VPN session started
  function build113039(ts) {
    const user    = pick(VPN_USERS);
    const group   = pick(VPN_GROUPS);
    const remoteIp = randomIp(pick(EXTERNAL_SUBNETS));
    const vpnIp   = `172.16.5.${randomInt(10, 250)}`;
    const msg = `Group ${group} User ${user} IP ${remoteIp} AnyConnect parent session started.`;
    return { line: makeSyslogLine(6, '113039', HOSTNAME, msg, ts), msgid: '113039', action: 'vpn-start', src_ip: remoteIp, user, group, vpn_ip: vpnIp };
  }

  // 113019 — VPN session disconnected
  function build113019(ts) {
    const user    = pick(VPN_USERS);
    const group   = pick(VPN_GROUPS);
    const remoteIp = randomIp(pick(EXTERNAL_SUBNETS));
    const sessionType = pick(['AnyConnect-Parent', 'SSL-Tunnel', 'DTLS-Tunnel']);
    const duration = `${randomInt(0,8)}:${pad(randomInt(0,59))}:${pad(randomInt(0,59))}`;
    const bytesXmt = randomInt(10000, 5000000);
    const bytesRcv = randomInt(10000, 5000000);
    const reasons  = ['User Requested', 'Idle Timeout', 'Max time exceeded', 'Certificate Expired', 'IKE Delete', 'Administrator Reset'];
    const reason   = pick(reasons);
    const msg = `Group = ${group}, Username = ${user}, IP = ${remoteIp}, Session disconnected. Session Type: ${sessionType}, Duration: ${duration}, Bytes xmt: ${bytesXmt}, Bytes rcv: ${bytesRcv}, Reason: ${reason}`;
    return { line: makeSyslogLine(4, '113019', HOSTNAME, msg, ts), msgid: '113019', action: 'vpn-disconnect', src_ip: remoteIp, user, group, session_type: sessionType, bytes_sent: bytesXmt, bytes_received: bytesRcv, reason };
  }

  // 113005 — AAA user authentication rejected
  function build113005(ts) {
    const user    = pick(VPN_USERS);
    const server  = `10.0.2.${randomInt(10, 50)}`;
    const remoteIp = randomIp(pick(EXTERNAL_SUBNETS));
    const msg = `AAA user authentication Rejected : reason = Invalid password : server = ${server} : user = ${user}`;
    return { line: makeSyslogLine(3, '113005', HOSTNAME, msg, ts), msgid: '113005', action: 'auth-failed', src_ip: remoteIp, user, server };
  }

  // NEW: 400xxx / 733100 — IPS/Snort intrusion events (Firepower style)
  function buildIPSEvent(ts) {
    const sig    = pick(IPS_SIGNATURES);
    const src    = pick(EXTERNAL_SUBNETS);
    const dst    = pick(INTERNAL_SUBNETS);
    const srcIp  = randomIp(src);
    const dstIp  = randomIp(dst);
    const srcPort = randomInt(1024, 65535);
    const dstPort = pick([80, 443, 22, 445, 3389, 1433, 53]);
    // Cisco Firepower IPS events are reported via syslog as %ASA-1-733100 or %FTD-2-430003
    const useFTD  = Math.random() < 0.5;
    const device  = useFTD ? 'FTD-EDGE-01' : HOSTNAME;
    const prefix  = useFTD ? '%FTD' : '%ASA';
    const msgid   = useFTD ? '430003' : '733100';
    const pri     = 16 * 8 + sig.sev;
    const impact  = pick(['Vulnerable', 'Currently Not Vulnerable', 'Unknown']);
    let msg;
    if (useFTD) {
      msg = `AC ${sig.priority} ${sig.msg} {${srcIp}:${srcPort} -> ${dstIp}:${dstPort}} [Impact: ${impact}]${sig.cve ? ' CVE: ' + sig.cve : ''}`;
    } else {
      msg = `Object dropped. SID: ${sig.sid}, Message: ${sig.msg}, Src: ${srcIp}/${srcPort}, Dst: ${dstIp}/${dstPort}, Priority: ${sig.priority}${sig.cve ? ', CVE: ' + sig.cve : ''}`;
    }
    const line = `<${pri}>${fmtTimestamp(ts)} ${device} : ${prefix}-${sig.sev}-${msgid}: ${msg}`;
    return { line, msgid, action: 'ips-drop', protocol: 'TCP', src_ip: srcIp, src_port: srcPort, dst_ip: dstIp, dst_port: dstPort, ips_sid: sig.sid, ips_msg: sig.msg, ips_priority: sig.priority, cve: sig.cve };
  }

  // NEW: Platform/system events
  function buildSystemEvent(ts) {
    const ev   = pick(SYSTEM_EVENTS);
    const pri  = 16 * 8 + ev.sev;
    const line = `<${pri}>${fmtTimestamp(ts)} ${HOSTNAME} : %ASA-${ev.sev}-${ev.msgid}: ${ev.msg}`;
    return { line, msgid: ev.msgid, action: 'system', src_ip: '', dst_ip: '' };
  }

  const logLines  = [];
  const parsed    = [];
  const summary   = { total: LOG_COUNT, byMsgId: {}, byAction: {} };

  for (let i = 0; i < LOG_COUNT; i++) {
    const now = new Date();
    const offset = Math.floor((i / LOG_COUNT) * 3600 * 1000);
    const ts = new Date(now.getTime() - 3600000 + offset);

    let result;
    const roll = Math.random();
    if (roll < 0.20) {
      result = build302013(ts);
    } else if (roll < 0.32) {
      result = build302014(ts);
    } else if (roll < 0.42) {
      result = build302015(ts);
    } else if (roll < 0.47) {
      result = build302016(ts);
    } else if (roll < 0.60) {
      result = build106023(ts);
    } else if (roll < 0.70) {
      result = build106100(ts);
    } else if (roll < 0.77) {
      result = build710003(ts);
    } else if (roll < 0.82) {
      result = build113039(ts);
    } else if (roll < 0.87) {
      result = build113019(ts);
    } else if (roll < 0.90) {
      result = build113005(ts);
    } else if (roll < 0.96) {
      result = buildIPSEvent(ts);
    } else {
      result = buildSystemEvent(ts);
    }

    logLines.push(result.line);
    parsed.push({ ...result, timestamp: ts.toISOString() });
    summary.byMsgId[result.msgid]   = (summary.byMsgId[result.msgid] || 0) + 1;
    summary.byAction[result.action] = (summary.byAction[result.action] || 0) + 1;
  }

  console.log(`Generated ${LOG_COUNT} Cisco ASA/FTD syslog entries.`);
  console.log(`  By msgid: ${JSON.stringify(summary.byMsgId)}`);
  console.log(`  By action: ${JSON.stringify(summary.byAction)}`);

  return { logLines, parsed, summary };
}

import { execution } from '@dynatrace-sdk/automation-utils';
import { logsClient } from '@dynatrace-sdk/client-classic-environment-v2';

const BATCH_SIZE = 20;

export default async function ({ execution_id }) {
  const ex = await execution();
  const genResult = await ex.result('generate_cisco_asa_logs');
  const logLines  = genResult.logLines;
  const parsed    = genResult.parsed;
  const summary   = genResult.summary;

  const severityMap = {
    1: 'ERROR', 2: 'ERROR', 3: 'ERROR',
    4: 'WARN',  5: 'INFO',  6: 'INFO', 7: 'DEBUG',
  };

  function extractSeverity(line) {
    const m = line.match(/%-?(?:ASA|FTD)-(\d+)-/);
    if (m) return parseInt(m[1]);
    return 6;
  }

  function extractMsgId(line) {
    const m = line.match(/%-?(?:ASA|FTD)-\d+-(\d+):/);
    return m ? m[1] : 'unknown';
  }

  const logEntries = [];
  for (let i = 0; i < logLines.length; i++) {
    const line = logLines[i];
    const meta = parsed[i];
    const sevLevel  = extractSeverity(line);
    const msgId     = extractMsgId(line);
    const severity  = severityMap[sevLevel] || 'INFO';

    const entry = {
      'content':              line,
      'log.source':           'cisco-asa',
      'log.tag':              'demo-log-generator',
      'severity':             severity,
      'source_vendor':        'Cisco',
      'source_product':       line.includes('%FTD') ? 'FTD' : 'ASA',
      'env':                  'demo',
      'hostname':             line.includes('FTD-EDGE') ? 'FTD-EDGE-01' : 'ASA-EDGE-01',
      'cisco.message_id':     msgId,
      'cisco.severity_level': sevLevel,
      'cisco.action':         meta.action || '',
      'cisco.src_ip':         meta.src_ip || '',
      'cisco.dst_ip':         meta.dst_ip || '',
      'cisco.protocol':       meta.protocol || '',
    };

    if (meta.src_port)      entry['cisco.src_port']       = meta.src_port;
    if (meta.dst_port)      entry['cisco.dst_port']       = meta.dst_port;
    if (meta.conn_id)       entry['cisco.connection_id']  = meta.conn_id;
    if (meta.acl)           entry['cisco.acl_name']       = meta.acl;
    if (meta.user)          entry['cisco.user']           = meta.user;
    if (meta.group)         entry['cisco.group']          = meta.group;
    if (meta.reason)        entry['cisco.reason']         = meta.reason;
    if (meta.bytes)         entry['cisco.bytes']          = meta.bytes;
    if (meta.bytes_sent)    entry['cisco.bytes_sent']     = meta.bytes_sent;
    if (meta.bytes_received) entry['cisco.bytes_received'] = meta.bytes_received;
    if (meta.session_type)  entry['cisco.session_type']   = meta.session_type;
    if (meta.server)        entry['cisco.aaa_server']     = meta.server;
    // IPS fields
    if (meta.ips_sid)       entry['cisco.ips_sid']        = meta.ips_sid;
    if (meta.ips_msg)       entry['cisco.ips_msg']        = meta.ips_msg;
    if (meta.ips_priority)  entry['cisco.ips_priority']   = meta.ips_priority;
    if (meta.cve)           entry['cisco.cve']            = meta.cve;

    logEntries.push(entry);
  }

  let ingested = 0;
  const errors = [];
  for (let i = 0; i < logEntries.length; i += BATCH_SIZE) {
    const batch = logEntries.slice(i, i + BATCH_SIZE);
    try {
      await logsClient.storeLog({
        type: 'application/json; charset=utf-8',
        body: batch,
      });
      ingested += batch.length;
      console.log(`Batch ${Math.floor(i/BATCH_SIZE)+1}: ingested ${batch.length} entries.`);
    } catch (e) {
      const msg = `Batch ${Math.floor(i/BATCH_SIZE)+1} failed: ${e.message}`;
      console.error(msg);
      errors.push(msg);
    }
  }

  console.log(`Ingested ${ingested}/${logEntries.length} Cisco ASA/FTD log entries into Grail.`);
  return { totalIngested: ingested, totalAttempted: logEntries.length, summary, errors };
}

import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const ex = await execution();
  const genResult = await ex.result('generate_cisco_asa_logs');
  const parsed    = genResult.parsed;
  const summary   = genResult.summary;

  const denyEvents    = parsed.filter(e => ['deny', 'auth-failed'].includes(e.action));
  const permitEvents  = parsed.filter(e => e.action === 'permit');
  const connEvents    = parsed.filter(e => e.action === 'built');
  const teardownEvents = parsed.filter(e => e.action === 'teardown');
  const vpnEvents     = parsed.filter(e => e.action.startsWith('vpn'));

  const topDeniedSrc = {};
  for (const e of denyEvents) {
    if (e.src_ip) topDeniedSrc[e.src_ip] = (topDeniedSrc[e.src_ip] || 0) + 1;
  }
  const topDenied = Object.entries(topDeniedSrc)
    .sort((a,b) => b[1]-a[1]).slice(0,10)
    .map(([ip, count]) => ({ ip, count }));

  const byDstPort = {};
  for (const e of denyEvents) {
    if (e.dst_port) byDstPort[e.dst_port] = (byDstPort[e.dst_port] || 0) + 1;
  }

  const report = {
    total:         parsed.length,
    byMsgId:       summary.byMsgId,
    byAction:      summary.byAction,
    denyCount:     denyEvents.length,
    permitCount:   permitEvents.length,
    connBuilt:     connEvents.length,
    connTeardown:  teardownEvents.length,
    vpnEvents:     vpnEvents.length,
    topDeniedSrcIPs: topDenied,
    denyByDstPort:   byDstPort,
    validationResult: parsed.length > 0
      ? `PASS - ${parsed.length} entries. Deny: ${denyEvents.length}, Permit: ${permitEvents.length}, Connections: ${connEvents.length+teardownEvents.length}, VPN: ${vpnEvents.length}`
      : 'FAIL - No log entries generated',
  };

  console.log(`Cisco ASA analysis: ${report.validationResult}`);
  return report;
}
